/**
 * Type surface for the vendored, esbuild-bundled Bot planner core (vendor/
 * planner.js, generated by scripts/build-planner.mjs from
 * Bot/src/lib/planner/server.ts). Hand-maintained; keep in sync with that entry.
 *
 * Only the pure server surface is exposed: `planForServer` + `PLAN_VERSION`.
 */

/** Terrain reader: `get(x,y)` → 0 (plain) | 1 (wall) | 2 (swamp). */
export interface TerrainLike {
  get(x: number, y: number): number;
}

/** Input to the pure planner — a plain object the Strategist assembles from the
 *  room-terrain + room-objects API responses. */
export interface BuildPlanInput {
  terrain: TerrainLike;
  sources: Array<{ x: number; y: number }>;
  controller: { x: number; y: number } | null;
  mineral: { x: number; y: number; mineralType?: string } | null;
  spawn: { x: number; y: number } | null;
  /** Existing structures (excluding ramparts), as `{ x, y, type }` where type is
   *  a Screeps structureType string (e.g. "spawn", "extension", "container"). */
  existing: Array<{ x: number; y: number; type: string }>;
  storagePos?: { x: number; y: number } | null;
  mincutMargin?: number;
  exitMargin?: number;
  /** Defaults true; the server keeps the adaptive fitter on. */
  allowFitter?: boolean;
}

/** Compact wire format stored in RawMemory segment 90 (roomName → PackedPlan).
 *  Coords are packed x*50+y; structure type is an index into the planner's TYPES
 *  table. Mirrors Bot/src/lib/planner/types.ts#PackedPlan. */
export interface PackedPlan {
  v: number;
  at: number;
  a: number;
  s: Array<[number, number, number, number?]>;
  r: number[];
  d: number[];
}

/** The plan schema version the in-game bot expects (segment plans whose `v`
 *  differs are ignored + recomputed). */
export const PLAN_VERSION: number;

/**
 * Compute + pack a base plan for one room, server-side (pure; no game runtime).
 * `at` stamps the plan's provenance tick. Returns null only when the room admits
 * no plan at all.
 */
export function planForServer(input: BuildPlanInput, at?: number): PackedPlan | null;
